 71→/**
 72→ * Get AI investment by project - where is time being spent?
 73→ */
 74→export async function getProjectInvestment(
 75→	orgId: string,
 76→	params: {
 77→		days?: number;
 78→		limit?: number;
 79→		offset?: number;
 80→		project_path?: string;
 81→		project_paths?: string[];
 82→	} = {},
 83→): Promise<ProjectInvestment[]> {
 84→	const {
 85→		days = 30,
 86→		limit = 20,
 87→		offset = 0,
 88→		project_path,
 89→		project_paths,
 90→	} = params;
 91→	const org = escapeString(orgId);
 92→	const d = Number(days);
 93→	const lim = Number(limit);
 94→	const off = Number(offset);
 95→
 96→	let projectFilter = "";
 97→	if (project_path) {
 98→		projectFilter = `AND project_path = '${escapeString(project_path)}'`;
 99→	} else if (project_paths && project_paths.length > 0) {
100→		const escaped = project_paths.map((p) => `'${escapeString(p)}'`).join(", ");
101→		projectFilter = `AND project_path IN (${escaped})`;
102→	}
103→
104→	const query = `
105→    WITH current_period AS (
106→      SELECT
107→        repository,
108→        any(project_path) as project_path,
109→        COUNT(*) as sessions,
110→        COUNT(DISTINCT user_id) as unique_users,
111→        SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
112→        SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
113→        SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
114→        round(SUM(actual_duration_min), 2) as total_duration_min,
115→        round(AVG(actual_duration_min), 2) as avg_session_duration_min,
116→        round(AVG(success_score), 2) as success_rate
117→      FROM rudel.session_analytics
118→      WHERE ${buildDateFilter(d)}
119→        AND organization_id = '${org}'
120→        AND repository != ''
121→        ${projectFilter}
122→      GROUP BY repository
123→    ),
124→    previous_period AS (
125→      SELECT
126→        repository,
127→        round(AVG(success_score), 2) as prev_success_rate
128→      FROM rudel.session_analytics
129→      WHERE session_date >= now64(3) - INTERVAL ${d * 2} DAY
130→        AND session_date < now64(3) - INTERVAL ${d} DAY
131→        AND organization_id = '${org}'
132→        AND repository != ''
133→        ${projectFilter}
134→      GROUP BY repository
135→    )
136→    SELECT
137→      c.repository,
138→      c.project_path,
139→      c.sessions,
140→      c.unique_users,
141→      c.total_tokens,
142→      c.input_tokens_sum as input_tokens,
143→      c.output_tokens_sum as output_tokens,
144→      c.total_duration_min,
145→      c.avg_session_duration_min,
146→      c.success_rate,
147→      round((c.output_tokens_sum / 1000000.0) * 15.0 + (c.input_tokens_sum / 1000000.0) * 3.0, 4) as cost,
148→      round(c.success_rate - ifNull(p.prev_success_rate, c.success_rate), 2) as success_rate_trend
149→    FROM current_period c
150→    LEFT JOIN previous_period p ON c.repository = p.repository
151→    ORDER BY c.total_duration_min DESC
152→    LIMIT ${lim}
153→    OFFSET ${off}
154→  `;
155→
156→	const results = await queryClickhouse<ProjectInvestment>(query);
157→
158→	return results.map((project) => ({
159→		...project,
160→		repository: project.repository || null,
161→	}));
162→}
