526→/**
527→ * Get error patterns specific to a project
528→ */
529→export async function getProjectErrors(
530→	orgId: string,
531→	projectPath: string,
532→	days = 30,
533→): Promise<ProjectError[]> {
534→	const org = escapeString(orgId);
535→	const pp = escapeString(projectPath);
536→	const d = Number(days);
537→
538→	const query = `
539→    WITH project_repository AS (
540→      SELECT repository
541→      FROM rudel.session_analytics
542→      WHERE project_path = '${pp}'
543→        AND repository != ''
544→        AND organization_id = '${org}'
545→      LIMIT 1
546→    ),
547→    error_extracts AS (
548→      SELECT
549→        session_id,
550→        user_id,
551→        session_date,
552→        CASE
553→          WHEN content LIKE '%OperationFailed%' THEN 'OperationFailed'
554→          WHEN content LIKE '%UnknownError%' THEN 'UnknownError'
555→          WHEN content LIKE '%ORPCError%' THEN 'ORPCError'
556→          WHEN content LIKE '%TimeoutError%' THEN 'TimeoutError'
557→          WHEN content LIKE '%TypeError%' THEN 'TypeError'
558→          WHEN content LIKE '%ReferenceError%' THEN 'ReferenceError'
559→          WHEN content LIKE '%Error:%' OR content LIKE '%error:%' THEN 'GenericError'
560→          ELSE NULL
561→        END as error_pattern
562→      FROM rudel.session_analytics
563→      WHERE repository = (SELECT repository FROM project_repository)
564→        AND ${buildDateFilter(d)}
565→        AND organization_id = '${org}'
566→        AND (content LIKE '%Error:%' OR content LIKE '%error:%')
567→    )
568→    SELECT
569→      error_pattern,
570→      COUNT(*) as occurrences,
571→      uniq(user_id) as affected_users,
572→      toString(min(session_date)) as first_seen,
573→      toString(max(session_date)) as last_seen
574→    FROM error_extracts
575→    WHERE error_pattern IS NOT NULL
576→    GROUP BY error_pattern
577→    ORDER BY occurrences DESC
578→    LIMIT 20
579→  `;
580→
581→	return queryClickhouse<ProjectError>(query);
582→}
